module checksum_calculator (
    input wire [7:0] data_in,
    input wire [7:0] expected_checksum,
    output reg [7:0] obf_calculated_checksum,
    output reg is_valid
);
    integer i;
    always @(*) begin
        obf_calculated_checksum = 0;
        for (i = 0; i < 8; i = i + 1) begin
            obf_calculated_checksum = obf_calculated_checksum + data_in[i];
        end
        obf_calculated_checksum = obf_calculated_checksum % 256;
        is_valid = (obf_calculated_checksum == expected_checksum);
    end
endmodule
